window.AIESS = window.AIESS || {}; AIESS.questions = AIESS.questions || [];
AIESS.questions.push(
{ id:"D5-001", domain:5, obj:"5.1", diff:"easy", q:"An employee wants an AI chatbot to help reword an email that contains a customer's full credit card number. What is the safest action?", options:["Remove the credit card number before pasting the email into the AI tool","Paste the full email so the AI has complete context","Add a note asking the AI to keep the card number private","Blur the card number in a screenshot and upload the image"], answer:0, explain:"<strong>Remove the credit card number before pasting the email into the AI tool</strong> is safest because financial data entered into a public AI service can be stored, exposed in a breach, or used for training, so it should never be shared.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paste the full email so the AI has complete context</b>: full context is not worth exposing a customer's card number to a third-party service.</span><span class='qd'><b>Add a note asking the AI to keep the card number private</b>: a request in the prompt does not control how the vendor stores or processes the data you submitted.</span><span class='qd'><b>Blur the card number in a screenshot and upload the image</b>: the sensitive data still leaves your control and blurring can be imperfect or reversible.</span>" },
{ id:"D5-002", domain:5, obj:"5.1", diff:"easy", q:"Before using a new free AI writing assistant for work notes, what should you read to understand how your data will be handled?", options:["The marketing homepage","The privacy policy and terms of use","The list of famous customers","The pricing page"], answer:1, explain:"<strong>The privacy policy and terms of use</strong> explain whether your inputs are stored, shared, or used to train the model, which is exactly what you need to know before entering any work data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The marketing homepage</b>: marketing pages promote features but rarely disclose data-handling practices.</span><span class='qd'><b>The list of famous customers</b>: notable customers say nothing about how your specific data is protected.</span><span class='qd'><b>The pricing page</b>: pricing tells you cost, not how your submitted information is used or retained.</span>" },
{ id:"D5-003", domain:5, obj:"5.1", diff:"easy", q:"Which of the following is generally the riskiest thing to type into a public AI chatbot?", options:["A publicly available news headline","A question about how photosynthesis works","Your company's internal database passwords","A recipe you found online"], answer:2, explain:"<strong>Your company's internal database passwords</strong> are secret credentials that could grant attackers access to systems, and entering them into a third-party service can expose them permanently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A publicly available news headline</b>: public information is already available to everyone and carries no exposure risk.</span><span class='qd'><b>A question about how photosynthesis works</b>: a general knowledge question contains no sensitive data.</span><span class='qd'><b>A recipe you found online</b>: a public recipe reveals nothing confidential about you or your organization.</span>" },
{ id:"D5-004", domain:5, obj:"5.1", diff:"medium", q:"A coworker says, &quot;It's fine to paste our patient records into any AI tool as long as I delete the chat afterward.&quot; Why is this reasoning flawed?", options:["Deleting the chat improves the AI's accuracy","Deleting a chat does not guarantee the data was not already stored, logged, or used for training","Patient records are never considered sensitive","The AI cannot read medical terminology"], answer:1, explain:"<strong>Deleting a chat does not guarantee the data was not already stored, logged, or used for training</strong>, so the sensitive records may persist on the vendor's servers regardless of what you see in your interface.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deleting the chat improves the AI's accuracy</b>: deleting a conversation has nothing to do with model accuracy.</span><span class='qd'><b>Patient records are never considered sensitive</b>: patient records are highly sensitive and protected under laws like HIPAA.</span><span class='qd'><b>The AI cannot read medical terminology</b>: modern AI tools handle medical language easily, and that is not the concern here.</span>" },
{ id:"D5-005", domain:5, obj:"5.1", diff:"medium", q:"You want AI help summarizing a contract, but it contains client names and dollar amounts your company treats as confidential. What is the best approach?", options:["Redact or replace the confidential details with placeholders before submitting","Submit the full contract because summaries are low risk","Email the contract to yourself first, then paste it","Only submit the confidential parts so the summary is accurate"], answer:0, explain:"<strong>Redact or replace the confidential details with placeholders before submitting</strong> lets you get useful help while keeping identifying names and figures out of a third-party system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Submit the full contract because summaries are low risk</b>: summarizing does not reduce the risk that confidential data was exposed by being submitted.</span><span class='qd'><b>Email the contract to yourself first, then paste it</b>: emailing it to yourself does nothing to protect the data once it is pasted into the AI tool.</span><span class='qd'><b>Only submit the confidential parts so the summary is accurate</b>: submitting the confidential parts is the exact thing that creates the exposure risk.</span>" },
{ id:"D5-006", domain:5, obj:"5.1", diff:"medium", q:"An AI service's privacy policy states that user inputs &quot;may be used to improve our models.&quot; What does this most directly mean for you?", options:["Your inputs are automatically encrypted end-to-end","What you type could become part of the training data and influence future outputs","The service will pay you for your data","Your inputs are deleted immediately after each session"], answer:1, explain:"<strong>What you type could become part of the training data and influence future outputs</strong> is the direct meaning, so you should assume anything you submit may be retained and reused and avoid entering sensitive material.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Your inputs are automatically encrypted end-to-end</b>: using data for training says nothing about encryption and does not imply it.</span><span class='qd'><b>The service will pay you for your data</b>: policies allowing training use do not mean you are compensated.</span><span class='qd'><b>Your inputs are deleted immediately after each session</b>: using inputs to improve models implies retention, the opposite of immediate deletion.</span>" },
{ id:"D5-007", domain:5, obj:"5.1", diff:"hard", q:"A salesperson pastes an entire spreadsheet of customer emails and phone numbers into a public AI tool to draft a marketing message. Which risk is MOST directly created?", options:["The AI will refuse to process spreadsheets","A data leak exposing customers' personal contact information to a third party","The marketing message will be grammatically incorrect","The spreadsheet file will be corrupted"], answer:1, explain:"<strong>A data leak exposing customers' personal contact information to a third party</strong> is the core risk, because personal data submitted to an outside service leaves the company's control and may be stored or breached.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI will refuse to process spreadsheets</b>: most AI tools readily accept pasted spreadsheet data, so refusal is not the concern.</span><span class='qd'><b>The marketing message will be grammatically incorrect</b>: grammar quality is unrelated to the privacy exposure the action creates.</span><span class='qd'><b>The spreadsheet file will be corrupted</b>: pasting data into a chatbot does not corrupt the source file.</span>" },
{ id:"D5-008", domain:5, obj:"5.1", diff:"medium", q:"Which statement best describes why free AI tools can pose a privacy concern?", options:["They always run offline on your device","The provider may collect, store, and analyze the data you enter","They cannot connect to the internet","They only work with public data"], answer:1, explain:"<strong>The provider may collect, store, and analyze the data you enter</strong> because many free services fund themselves through data usage, meaning your inputs can be retained and studied.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They always run offline on your device</b>: most free AI chatbots send your data to remote servers, not process it locally.</span><span class='qd'><b>They cannot connect to the internet</b>: these tools generally require an internet connection to function.</span><span class='qd'><b>They only work with public data</b>: the tools accept whatever you type, including private data, which is the concern.</span>" },
{ id:"D5-009", domain:5, obj:"5.1", diff:"easy", q:"Which of these is an example of sensitive personal data you should avoid entering into a public AI tool?", options:["A coworker's Social Security number","The current weather forecast","A definition of the word 'synergy'","A list of national holidays"], answer:0, explain:"<strong>A coworker's Social Security number</strong> is highly sensitive personal data that could enable identity theft if exposed, so it must never be entered into a public AI service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The current weather forecast</b>: weather is public information with no privacy implications.</span><span class='qd'><b>A definition of the word 'synergy'</b>: a dictionary definition is public knowledge and harmless to share.</span><span class='qd'><b>A list of national holidays</b>: holiday dates are publicly available and contain nothing sensitive.</span>" },
{ id:"D5-010", domain:5, obj:"5.1", diff:"hard", q:"Your company adopted an enterprise AI platform that contractually guarantees your data is not used for training. A colleague still prefers a random free web app for the same work. What is the best guidance?", options:["Both are equally safe since they use AI","Use the enterprise platform because its data-protection guarantees reduce exposure risk","Use the free app because it is faster to open","Alternate between them to avoid detection"], answer:1, explain:"<strong>Use the enterprise platform because its data-protection guarantees reduce exposure risk</strong>, since a contractual no-training commitment and vetted controls protect company data far better than an unknown free app.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Both are equally safe since they use AI</b>: using AI does not make two services equally trustworthy; their data handling differs greatly.</span><span class='qd'><b>Use the free app because it is faster to open</b>: convenience does not justify exposing company data to an unvetted service.</span><span class='qd'><b>Alternate between them to avoid detection</b>: deliberately evading oversight is itself a policy violation and increases risk.</span>" },
{ id:"D5-011", domain:5, obj:"5.2", diff:"easy", q:"You ask an AI image generator to create a company logo. Before using the result commercially, what should you check?", options:["Whether the output is copyrighted or whether you have rights to use it","The color of the background only","How many words were in your prompt","Whether the image loads quickly"], answer:0, explain:"<strong>Whether the output is copyrighted or whether you have rights to use it</strong> matters because AI-generated content can raise ownership and licensing questions, and the provider's terms may limit commercial use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The color of the background only</b>: background color is an aesthetic detail, not a legal-usage concern.</span><span class='qd'><b>How many words were in your prompt</b>: prompt length has no bearing on your legal right to use the image.</span><span class='qd'><b>Whether the image loads quickly</b>: load speed is a technical detail unrelated to usage rights.</span>" },
{ id:"D5-012", domain:5, obj:"5.2", diff:"medium", q:"An AI tool produces marketing copy that closely paraphrases a competitor's copyrighted brochure. What is the responsible next step?", options:["Publish it immediately since AI wrote it","Review and revise it to ensure it does not infringe copyrighted material","Add the competitor's logo to make it look official","Assume AI output is always original and legally safe"], answer:1, explain:"<strong>Review and revise it to ensure it does not infringe copyrighted material</strong> is responsible because AI can reproduce protected material, and you remain accountable for what you publish.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish it immediately since AI wrote it</b>: AI authorship does not shield you from copyright liability.</span><span class='qd'><b>Add the competitor's logo to make it look official</b>: using a competitor's logo is trademark infringement and worsens the problem.</span><span class='qd'><b>Assume AI output is always original and legally safe</b>: AI output can copy or closely mirror existing protected works, so it is not automatically safe.</span>" },
{ id:"D5-013", domain:5, obj:"5.2", diff:"medium", q:"Why should you verify the terms of use before using AI-generated content in a paid client project?", options:["Terms of use never mention commercial rights","Some AI services restrict or prohibit commercial use of their outputs","Terms of use guarantee the content is award-winning","Reading terms voids your account"], answer:1, explain:"<strong>Some AI services restrict or prohibit commercial use of their outputs</strong>, so checking the terms prevents you from unknowingly violating the license in a paid deliverable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Terms of use never mention commercial rights</b>: commercial-use rights are exactly the kind of thing terms of use address.</span><span class='qd'><b>Terms of use guarantee the content is award-winning</b>: terms govern usage rights, not quality claims.</span><span class='qd'><b>Reading terms voids your account</b>: reading the terms has no effect on your account status.</span>" },
{ id:"D5-014", domain:5, obj:"5.2", diff:"easy", q:"An AI tool generates an essay that includes specific facts and quotes. To use it responsibly in a published article, you should:", options:["Verify the facts and give proper attribution where required","Publish without checking since AI is reliable","Claim you personally interviewed the sources","Delete all citations to keep it simple"], answer:0, explain:"<strong>Verify the facts and give proper attribution where required</strong> upholds accuracy and honesty, since AI can fabricate quotes and you are responsible for crediting real sources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish without checking since AI is reliable</b>: AI can produce false or invented information, so unchecked publishing is risky.</span><span class='qd'><b>Claim you personally interviewed the sources</b>: fabricating interviews is dishonest and unethical.</span><span class='qd'><b>Delete all citations to keep it simple</b>: removing needed attribution can amount to plagiarism.</span>" },
{ id:"D5-015", domain:5, obj:"5.2", diff:"hard", q:"A designer feeds a well-known artist's copyrighted images into an AI to generate &quot;a piece in that exact style&quot; for a commercial ad. What is the primary legal concern?", options:["The AI will run too slowly","Using copyrighted works to closely mimic an identifiable artist may raise infringement and rights issues","The ad will be too colorful","The artist will be flattered and grant permission"], answer:1, explain:"<strong>Using copyrighted works to closely mimic an identifiable artist may raise infringement and rights issues</strong>, because feeding in protected images and reproducing a distinctive style commercially can violate the artist's rights.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI will run too slowly</b>: performance is irrelevant to the legal question of using protected works.</span><span class='qd'><b>The ad will be too colorful</b>: aesthetic outcome is not a legal concern.</span><span class='qd'><b>The artist will be flattered and grant permission</b>: assuming permission without asking does not create a legal right to use the style.</span>" },
{ id:"D5-016", domain:5, obj:"5.2", diff:"medium", q:"Which practice best respects intellectual property when using AI to help write a report?", options:["Copy AI output verbatim and present it as fully your own without any review","Use AI to draft, then verify sources and cite any borrowed material appropriately","Include screenshots of paywalled articles in the report","Remove all references so no one can check the sources"], answer:1, explain:"<strong>Use AI to draft, then verify sources and cite any borrowed material appropriately</strong> respects intellectual property by ensuring credit is given and that borrowed content is properly attributed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Copy AI output verbatim and present it as fully your own without any review</b>: skipping review can pass along uncredited or inaccurate material.</span><span class='qd'><b>Include screenshots of paywalled articles in the report</b>: reproducing paywalled content without permission can infringe copyright.</span><span class='qd'><b>Remove all references so no one can check the sources</b>: hiding sources undermines honesty and can constitute plagiarism.</span>" },
{ id:"D5-017", domain:5, obj:"5.2", diff:"easy", q:"True or false: because an AI tool created a passage of text, you are automatically free to use it however you like with no legal considerations.", options:["True, AI content has no legal considerations","False, ownership, licensing, and terms of use can still apply","True, AI content is always public domain","False, but only if the passage is very long"], answer:1, explain:"<strong>False, ownership, licensing, and terms of use can still apply</strong> because AI-generated content is governed by the provider's terms and can raise copyright questions depending on inputs and jurisdiction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>True, AI content has no legal considerations</b>: AI content can carry real legal and licensing considerations.</span><span class='qd'><b>True, AI content is always public domain</b>: AI output is not automatically public domain and may be restricted by terms.</span><span class='qd'><b>False, but only if the passage is very long</b>: the length of the passage does not determine whether legal considerations apply.</span>" },
{ id:"D5-018", domain:5, obj:"5.2", diff:"hard", q:"A team plans to publish an AI-written blog under a real employee's byline without noting AI involvement, and their industry expects transparency. What is the main issue?", options:["The blog will load slowly","Failing to disclose AI use where transparency is expected can mislead readers and breach ethics or policy","AI writing is always higher quality","Bylines are legally required to be fictional"], answer:1, explain:"<strong>Failing to disclose AI use where transparency is expected can mislead readers and breach ethics or policy</strong>, because presenting AI content as fully human-authored can be deceptive when disclosure is expected.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The blog will load slowly</b>: load time is irrelevant to the transparency issue.</span><span class='qd'><b>AI writing is always higher quality</b>: quality is not the concern, and AI output is not always superior.</span><span class='qd'><b>Bylines are legally required to be fictional</b>: there is no such requirement, and this misstates the situation.</span>" },
{ id:"D5-019", domain:5, obj:"5.2", diff:"medium", q:"You want to use an AI-generated photo in a company presentation. The tool's license says outputs may be used &quot;for personal, non-commercial purposes only.&quot; What should you do?", options:["Use it anyway since it is only an internal presentation","Respect the license and find a properly licensed image for commercial or business use","Crop the image so the license no longer applies","Assume business use counts as personal use"], answer:1, explain:"<strong>Respect the license and find a properly licensed image for commercial or business use</strong> because a business presentation is not personal use, and honoring license terms avoids infringement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use it anyway since it is only an internal presentation</b>: internal business use still falls outside a personal, non-commercial license.</span><span class='qd'><b>Crop the image so the license no longer applies</b>: cropping does not change the licensing terms attached to the content.</span><span class='qd'><b>Assume business use counts as personal use</b>: business use is distinct from personal use and is not covered by that license.</span>" },
{ id:"D5-020", domain:5, obj:"5.2", diff:"easy", q:"When AI generates content that borrows from existing sources, giving credit to those sources is an example of:", options:["Proper attribution","Data encryption","A backout plan","Multifactor authentication"], answer:0, explain:"<strong>Proper attribution</strong> means crediting the original sources of borrowed material, which is a core responsible-use and ethics practice.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data encryption</b>: encryption protects data confidentiality and has nothing to do with crediting sources.</span><span class='qd'><b>A backout plan</b>: a backout plan is a rollback procedure for changes, unrelated to attribution.</span><span class='qd'><b>Multifactor authentication</b>: multifactor authentication verifies identity and is unrelated to citing sources.</span>" },
{ id:"D5-021", domain:5, obj:"5.3", diff:"easy", q:"Your organization has an approved list of AI tools. You discover a different AI app you like better. What should you do first?", options:["Start using it immediately for all your work","Check with your manager or IT before using it for company work","Recommend it to every coworker right away","Install it on every company computer you can"], answer:1, explain:"<strong>Check with your manager or IT before using it for company work</strong> ensures the tool is vetted for security and compliance before company data touches it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Start using it immediately for all your work</b>: using an unapproved tool can violate policy and expose data.</span><span class='qd'><b>Recommend it to every coworker right away</b>: promoting an unvetted tool spreads potential risk before it is approved.</span><span class='qd'><b>Install it on every company computer you can</b>: installing unapproved software broadly is a serious policy and security violation.</span>" },
{ id:"D5-022", domain:5, obj:"5.3", diff:"easy", q:"A hospital employee wants to use AI to summarize patient charts. Which regulation most directly governs the handling of that health information?", options:["HIPAA","The speed limit","Building fire codes","Trademark law"], answer:0, explain:"<strong>HIPAA</strong> governs the privacy and security of protected health information in the United States, so it directly applies to handling patient charts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The speed limit</b>: traffic law has no relationship to health data.</span><span class='qd'><b>Building fire codes</b>: fire codes address physical safety, not data privacy.</span><span class='qd'><b>Trademark law</b>: trademark law protects brands and logos, not medical records.</span>" },
{ id:"D5-023", domain:5, obj:"5.3", diff:"medium", q:"A company operating in the European Union must protect personal data under which regulation when choosing AI tools?", options:["GDPR","HIPAA only","OSHA","The Geneva Convention"], answer:0, explain:"<strong>GDPR</strong> (the General Data Protection Regulation) governs personal data protection for individuals in the EU, so it applies when selecting AI tools that process such data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>HIPAA only</b>: HIPAA is a U.S. health-data law and is not the EU's general data protection regulation.</span><span class='qd'><b>OSHA</b>: OSHA governs workplace safety, not data privacy.</span><span class='qd'><b>The Geneva Convention</b>: the Geneva Convention concerns wartime conduct, not personal data.</span>" },
{ id:"D5-024", domain:5, obj:"5.3", diff:"medium", q:"Why is it important to use only company-approved AI tools rather than any tool you find online?", options:["Approved tools are always free","Approved tools have been vetted for security, privacy, and compliance requirements","Unapproved tools cannot generate text","Approved tools produce longer answers"], answer:1, explain:"<strong>Approved tools have been vetted for security, privacy, and compliance requirements</strong>, meaning the organization has assessed their data handling and legal fit before allowing their use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Approved tools are always free</b>: approval has nothing to do with cost; approved tools may be paid.</span><span class='qd'><b>Unapproved tools cannot generate text</b>: unapproved tools can generate text; the issue is vetting, not capability.</span><span class='qd'><b>Approved tools produce longer answers</b>: answer length is unrelated to whether a tool is approved.</span>" },
{ id:"D5-025", domain:5, obj:"5.3", diff:"hard", q:"An employee is unsure whether uploading a client list to an AI tool complies with the company's data policy. What is the most responsible action?", options:["Upload it and apologize later if there is a problem","Pause and consult the company's policy, manager, or IT/compliance before uploading","Assume it is fine because other coworkers do similar things","Delete the client list to avoid the decision"], answer:1, explain:"<strong>Pause and consult the company's policy, manager, or IT/compliance before uploading</strong> is responsible because confirming compliance before acting prevents a potential data or policy violation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Upload it and apologize later if there is a problem</b>: acting first and apologizing later can cause irreversible data exposure.</span><span class='qd'><b>Assume it is fine because other coworkers do similar things</b>: others' behavior does not confirm that the action complies with policy.</span><span class='qd'><b>Delete the client list to avoid the decision</b>: deleting needed business data is destructive and does not address the compliance question.</span>" },
{ id:"D5-026", domain:5, obj:"5.3", diff:"medium", q:"A manager asks you to draft a company policy for employee AI use. Which item is most important to include?", options:["The CEO's favorite color","Rules on what data may or may not be entered into AI tools","A list of every employee's home address","The office coffee brand"], answer:1, explain:"<strong>Rules on what data may or may not be entered into AI tools</strong> is essential because clear data-handling guidance prevents the accidental exposure of sensitive or regulated information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The CEO's favorite color</b>: a preference like this is irrelevant to an AI-use policy.</span><span class='qd'><b>A list of every employee's home address</b>: listing home addresses would itself be a privacy risk and is not a policy requirement.</span><span class='qd'><b>The office coffee brand</b>: workplace trivia has no bearing on responsible AI use.</span>" },
{ id:"D5-027", domain:5, obj:"5.3", diff:"easy", q:"If you are unsure whether a particular AI use is allowed at work, who is the appropriate person to ask?", options:["Your manager or IT/security team","A stranger on social media","No one, just guess","The AI chatbot itself for a final legal ruling"], answer:0, explain:"<strong>Your manager or IT/security team</strong> can give authoritative guidance on company policy and compliance, making them the right people to consult.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A stranger on social media</b>: strangers do not know your company's policies and may give unreliable advice.</span><span class='qd'><b>No one, just guess</b>: guessing on compliance matters can lead to violations.</span><span class='qd'><b>The AI chatbot itself for a final legal ruling</b>: an AI chatbot cannot render your company's official policy decision and may be wrong.</span>" },
{ id:"D5-028", domain:5, obj:"5.3", diff:"hard", q:"A financial firm wants employees to use AI but must follow strict regulations on client financial data. Which combined approach best balances productivity and compliance?", options:["Ban AI entirely with no exceptions","Approve vetted enterprise AI tools and train staff on what data is permitted","Let every employee choose any free AI tool","Ignore regulations because AI boosts output"], answer:1, explain:"<strong>Approve vetted enterprise AI tools and train staff on what data is permitted</strong> balances productivity and compliance by combining trusted tools with clear rules about handling regulated data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ban AI entirely with no exceptions</b>: a total ban sacrifices productivity when a controlled approach is possible.</span><span class='qd'><b>Let every employee choose any free AI tool</b>: unrestricted tool choice invites data exposure and regulatory violations.</span><span class='qd'><b>Ignore regulations because AI boosts output</b>: ignoring regulations exposes the firm to serious legal and financial penalties.</span>" },
{ id:"D5-029", domain:5, obj:"5.3", diff:"medium", q:"An employee wants to use a personal AI account for work tasks to avoid company monitoring. Why is this a compliance concern?", options:["Personal accounts run faster","It can bypass company security controls and place company data outside approved, compliant systems","Personal accounts have better spelling","It automatically encrypts everything"], answer:1, explain:"<strong>It can bypass company security controls and place company data outside approved, compliant systems</strong>, which undermines oversight and may violate policy and regulations governing that data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Personal accounts run faster</b>: speed is irrelevant and is not why this is a compliance concern.</span><span class='qd'><b>Personal accounts have better spelling</b>: spelling quality has nothing to do with the compliance risk.</span><span class='qd'><b>It automatically encrypts everything</b>: personal accounts do not necessarily encrypt data, and encryption would not resolve the oversight problem.</span>" },
{ id:"D5-030", domain:5, obj:"5.3", diff:"easy", q:"Which of these is a company policy you might expect to govern responsible AI use at work?", options:["Only use approved AI tools for handling company information","Everyone must use AI for every single task","Never verify any AI output","Share your login credentials with AI chatbots"], answer:0, explain:"<strong>Only use approved AI tools for handling company information</strong> is a sensible policy that keeps sensitive data within vetted, compliant systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Everyone must use AI for every single task</b>: mandating AI for everything is unrealistic and not a sound governance rule.</span><span class='qd'><b>Never verify any AI output</b>: responsible policy encourages verification, not skipping it.</span><span class='qd'><b>Share your login credentials with AI chatbots</b>: sharing credentials is a serious security risk, the opposite of good policy.</span>" },
{ id:"D5-031", domain:5, obj:"5.4", diff:"easy", q:"An AI assistant gives you a confident answer to a critical legal question for your business. What is the responsible way to use it?", options:["Act on it immediately without checking","Treat it as a starting point and verify with a qualified professional","Assume confidence means it is correct","Forward it to clients as official legal advice"], answer:1, explain:"<strong>Treat it as a starting point and verify with a qualified professional</strong> is responsible because AI can be confidently wrong, and high-stakes legal matters require expert confirmation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Act on it immediately without checking</b>: acting without verification on critical matters can cause serious harm if the answer is wrong.</span><span class='qd'><b>Assume confidence means it is correct</b>: AI often states incorrect information confidently, so tone is not proof of accuracy.</span><span class='qd'><b>Forward it to clients as official legal advice</b>: passing unverified AI output as professional legal advice is risky and potentially harmful.</span>" },
{ id:"D5-032", domain:5, obj:"5.4", diff:"easy", q:"When AI produces a confident but false statement, this is commonly referred to as a:", options:["Hallucination","Firewall","Backup","Handshake"], answer:0, explain:"<strong>Hallucination</strong> is the term for when an AI generates plausible-sounding but incorrect or fabricated information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Firewall</b>: a firewall is a network security control, not an AI error.</span><span class='qd'><b>Backup</b>: a backup is a copy of data for recovery, unrelated to false AI output.</span><span class='qd'><b>Handshake</b>: a handshake is a connection-setup process in networking, not an AI mistake.</span>" },
{ id:"D5-033", domain:5, obj:"5.4", diff:"medium", q:"You are using AI to help screen job applicants. Why should you not let the AI make the final hiring decision on its own?", options:["AI cannot read resumes at all","AI outputs can reflect bias or errors that unfairly affect people's opportunities","AI always hires the best candidate","Final decisions are faster when fully automated"], answer:1, explain:"<strong>AI outputs can reflect bias or errors that unfairly affect people's opportunities</strong>, so a human should review high-stakes decisions to guard against discrimination and mistakes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI cannot read resumes at all</b>: AI can process resumes; the concern is bias and error, not capability.</span><span class='qd'><b>AI always hires the best candidate</b>: AI does not guarantee the best choice and can perpetuate unfair patterns.</span><span class='qd'><b>Final decisions are faster when fully automated</b>: speed does not justify removing human judgment from consequential decisions.</span>" },
{ id:"D5-034", domain:5, obj:"5.4", diff:"medium", q:"An AI tool recommends denying a customer's loan based on patterns in past data. What is the biggest fairness risk?", options:["The recommendation may reflect historical bias that discriminates against certain groups","The tool will run out of memory","The customer will not read the letter","The interest rate font is too small"], answer:0, explain:"<strong>The recommendation may reflect historical bias that discriminates against certain groups</strong>, because AI trained on biased historical data can reproduce and amplify unfair patterns.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The tool will run out of memory</b>: a technical resource issue is not the fairness concern being raised.</span><span class='qd'><b>The customer will not read the letter</b>: whether the customer reads the letter is unrelated to fairness of the decision.</span><span class='qd'><b>The interest rate font is too small</b>: formatting details have nothing to do with bias in the recommendation.</span>" },
{ id:"D5-035", domain:5, obj:"5.4", diff:"hard", q:"A medical clinic uses AI to suggest diagnoses. Which policy best reflects responsible use in this high-stakes setting?", options:["The AI's diagnosis is final and cannot be questioned","A licensed clinician reviews and confirms every AI suggestion before it affects care","Patients receive AI diagnoses with no human involvement","The AI replaces all doctors to cut costs"], answer:1, explain:"<strong>A licensed clinician reviews and confirms every AI suggestion before it affects care</strong> keeps a qualified human accountable for decisions that directly affect patient safety.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI's diagnosis is final and cannot be questioned</b>: making AI unchallengeable in medicine is dangerous and removes essential oversight.</span><span class='qd'><b>Patients receive AI diagnoses with no human involvement</b>: removing clinicians risks acting on incorrect AI output in life-critical situations.</span><span class='qd'><b>The AI replaces all doctors to cut costs</b>: cost savings do not justify eliminating professional medical judgment.</span>" },
{ id:"D5-036", domain:5, obj:"5.4", diff:"medium", q:"You notice an AI tool consistently produces sexist descriptions of certain job roles. What is the responsible action?", options:["Keep using it and ignore the pattern","Report the biased behavior to the appropriate team and avoid relying on those outputs","Amplify the biased outputs to prove a point","Assume the bias is intentional and acceptable"], answer:1, explain:"<strong>Report the biased behavior to the appropriate team and avoid relying on those outputs</strong> is responsible because flagging bias helps address it and protects people from unfair or harmful content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep using it and ignore the pattern</b>: ignoring bias allows harmful outputs to continue unchecked.</span><span class='qd'><b>Amplify the biased outputs to prove a point</b>: spreading biased content causes harm rather than resolving the issue.</span><span class='qd'><b>Assume the bias is intentional and acceptable</b>: treating bias as acceptable normalizes discrimination and is not responsible.</span>" },
{ id:"D5-037", domain:5, obj:"5.4", diff:"easy", q:"What is the best mindset for using AI in important work decisions?", options:["AI is an assistant that supports human judgment, not the final authority","AI is always right and needs no oversight","AI should replace all human decision-making","AI output should never be questioned"], answer:0, explain:"<strong>AI is an assistant that supports human judgment, not the final authority</strong> reflects responsible use, keeping a human accountable for important decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI is always right and needs no oversight</b>: AI can be wrong, so oversight remains essential.</span><span class='qd'><b>AI should replace all human decision-making</b>: removing human judgment from important choices is risky and irresponsible.</span><span class='qd'><b>AI output should never be questioned</b>: questioning and verifying output is a core responsible-use habit.</span>" },
{ id:"D5-038", domain:5, obj:"5.4", diff:"hard", q:"An analyst pastes AI-generated statistics into a board report without checking them, and several figures turn out to be fabricated. What responsible practice was skipped?", options:["Encrypting the report","Verifying and fact-checking AI output before relying on it","Choosing a nicer font","Backing up the file"], answer:1, explain:"<strong>Verifying and fact-checking AI output before relying on it</strong> was skipped, and because AI can hallucinate figures, unchecked statistics led to inaccurate reporting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypting the report</b>: encryption protects confidentiality and would not have caught fabricated numbers.</span><span class='qd'><b>Choosing a nicer font</b>: formatting has no effect on the accuracy of the data.</span><span class='qd'><b>Backing up the file</b>: a backup preserves the file but does nothing to verify its contents.</span>" },
{ id:"D5-039", domain:5, obj:"5.4", diff:"medium", q:"Why is human review especially important when AI is used in high-stakes areas like healthcare, finance, or hiring?", options:["Because AI errors or bias in these areas can seriously harm people","Because AI cannot process numbers","Because human review makes AI slower for its own sake","Because these fields do not use computers"], answer:0, explain:"<strong>Because AI errors or bias in these areas can seriously harm people</strong>, human oversight is critical where mistakes affect health, money, or livelihoods.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because AI cannot process numbers</b>: AI can process numbers; the concern is the impact of errors, not capability.</span><span class='qd'><b>Because human review makes AI slower for its own sake</b>: review is not about slowing things down arbitrarily but about preventing harm.</span><span class='qd'><b>Because these fields do not use computers</b>: these fields rely heavily on computers, so this statement is false.</span>" },
{ id:"D5-040", domain:5, obj:"5.4", diff:"hard", q:"A company deploys an AI chatbot to give customers financial guidance. To use it responsibly, which safeguard is most important?", options:["Make the chatbot's advice legally binding on the company with no review","Clearly indicate AI limitations and route complex or high-stakes cases to a human expert","Remove all disclaimers so customers trust it more","Prevent customers from ever reaching a human"], answer:1, explain:"<strong>Clearly indicate AI limitations and route complex or high-stakes cases to a human expert</strong> protects customers by acknowledging the tool's limits and ensuring qualified review where it matters.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Make the chatbot's advice legally binding on the company with no review</b>: binding unreviewed AI advice invites serious errors and liability.</span><span class='qd'><b>Remove all disclaimers so customers trust it more</b>: hiding limitations misleads customers and increases risk.</span><span class='qd'><b>Prevent customers from ever reaching a human</b>: blocking human escalation is harmful for complex or sensitive situations.</span>" },
{ id:"D5-041", domain:5, obj:"5.5", diff:"easy", q:"You are learning a new spreadsheet skill and want an explanation tailored to your pace, with follow-up questions allowed. How can AI help here?", options:["As a patient, flexible tutor that explains concepts and adapts to your questions","By refusing to answer beginner questions","By making the topic more confusing on purpose","By only responding in a language you do not know"], answer:0, explain:"<strong>As a patient, flexible tutor that explains concepts and adapts to your questions</strong> is a strong use of AI, which can re-explain, give examples, and adjust to your level without judgment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>By refusing to answer beginner questions</b>: AI tutors are well suited to beginner questions, not refusing them.</span><span class='qd'><b>By making the topic more confusing on purpose</b>: a good learning aid clarifies rather than confuses.</span><span class='qd'><b>By only responding in a language you do not know</b>: responding in an unknown language would defeat the learning purpose.</span>" },
{ id:"D5-042", domain:5, obj:"5.5", diff:"easy", q:"You are stuck staring at a blank document for a report. How is AI especially useful for &quot;beating the blank page&quot;?", options:["It can brainstorm ideas and generate a rough first draft to build on","It guarantees the final report will win an award","It writes the report so you never have to review it","It prevents you from editing anything"], answer:0, explain:"<strong>It can brainstorm ideas and generate a rough first draft to build on</strong> is a classic strength of AI, giving you a starting point to overcome writer's block.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the final report will win an award</b>: AI cannot guarantee awards, and that is not the point of a first draft.</span><span class='qd'><b>It writes the report so you never have to review it</b>: you should always review AI drafts for accuracy and quality.</span><span class='qd'><b>It prevents you from editing anything</b>: AI drafts are meant to be edited, not locked from changes.</span>" },
{ id:"D5-043", domain:5, obj:"5.5", diff:"medium", q:"Which task is a good example of basic AI automation that can save time at work?", options:["Automatically drafting a summary of a long meeting transcript","Physically shredding paper documents","Rewiring the office network","Watering the office plants"], answer:0, explain:"<strong>Automatically drafting a summary of a long meeting transcript</strong> is a common AI automation that turns lengthy text into concise, useful notes quickly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physically shredding paper documents</b>: shredding is a physical task AI cannot perform.</span><span class='qd'><b>Rewiring the office network</b>: network rewiring is hands-on hardware work, not an AI text task.</span><span class='qd'><b>Watering the office plants</b>: watering plants is a physical chore unrelated to AI text automation.</span>" },
{ id:"D5-044", domain:5, obj:"5.5", diff:"medium", q:"A prompt like &quot;Give me 10 different angles for a blog post about remote work&quot; is an example of using AI to:", options:["Encrypt sensitive files","Configure a firewall","Brainstorm and generate ideas to overcome a creative block","Back up a database"], answer:2, explain:"<strong>Brainstorm and generate ideas to overcome a creative block</strong> describes idea generation, where asking for multiple angles helps you start and explore options.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypt sensitive files</b>: encryption is a security task, not idea generation.</span><span class='qd'><b>Configure a firewall</b>: firewall setup is a networking task unrelated to brainstorming.</span><span class='qd'><b>Back up a database</b>: creating a backup is a data-protection task, not creative brainstorming.</span>" },
{ id:"D5-045", domain:5, obj:"5.5", diff:"hard", q:"A project lead wants AI to reliably produce a weekly status email from raw notes. Which prompt pattern will most likely give consistent, useful drafts?", options:["Type a single word: 'email'","Ask for something completely different each week","Provide the notes plus clear instructions on tone, audience, and the sections to include","Give no notes and expect a full status update"], answer:2, explain:"<strong>Provide the notes plus clear instructions on tone, audience, and the sections to include</strong> gives the AI the context and structure it needs to produce consistent, useful drafts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Type a single word: 'email'</b>: a one-word prompt lacks the context needed for a usable status email.</span><span class='qd'><b>Ask for something completely different each week</b>: inconsistent requests undermine the goal of a reliable, repeatable format.</span><span class='qd'><b>Give no notes and expect a full status update</b>: without the source notes, the AI cannot accurately report status.</span>" },
{ id:"D5-046", domain:5, obj:"5.5", diff:"easy", q:"Which of the following is a good, low-risk workplace automation task for AI?", options:["Drafting captions for a set of product photos based on descriptions you provide","Making the final decision to fire an employee","Approving large financial transactions automatically","Diagnosing a patient with no doctor involved"], answer:0, explain:"<strong>Drafting captions for a set of product photos based on descriptions you provide</strong> is low-risk and easily reviewed, making it a good fit for AI automation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Making the final decision to fire an employee</b>: high-stakes personnel decisions require human judgment, not automation.</span><span class='qd'><b>Approving large financial transactions automatically</b>: automatic approval of large transactions is risky and needs human oversight.</span><span class='qd'><b>Diagnosing a patient with no doctor involved</b>: medical diagnosis without a clinician is dangerous and irresponsible.</span>" },
{ id:"D5-047", domain:5, obj:"5.5", diff:"medium", q:"How can AI act as a helpful teacher when you are learning a difficult concept?", options:["By explaining it in simpler terms and offering examples until it clicks","By giving only one explanation and refusing to rephrase","By hiding the answer until you pass a test","By insisting you already understand it"], answer:0, explain:"<strong>By explaining it in simpler terms and offering examples until it clicks</strong> shows AI's value as a patient tutor that can rephrase and illustrate concepts on demand.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>By giving only one explanation and refusing to rephrase</b>: a good tutor rephrases as needed rather than refusing.</span><span class='qd'><b>By hiding the answer until you pass a test</b>: withholding help does not aid learning a difficult concept.</span><span class='qd'><b>By insisting you already understand it</b>: dismissing your confusion does not help you learn.</span>" },
{ id:"D5-048", domain:5, obj:"5.5", diff:"hard", q:"An office manager wants to automate turning recorded meetings into action items and minutes. To use this responsibly, what should also be considered?", options:["Only the color of the meeting notes","Whether the AI can sing the notes aloud","Whether recording and processing the meeting complies with privacy rules and participant consent","How many chairs are in the room"], answer:2, explain:"<strong>Whether recording and processing the meeting complies with privacy rules and participant consent</strong> matters because automating minutes involves handling potentially sensitive discussion that may require consent and policy compliance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the color of the meeting notes</b>: note color is trivial and unrelated to responsible automation.</span><span class='qd'><b>Whether the AI can sing the notes aloud</b>: singing is irrelevant to producing minutes responsibly.</span><span class='qd'><b>How many chairs are in the room</b>: seating has nothing to do with privacy or consent for recordings.</span>" },
{ id:"D5-049", domain:5, obj:"5.5", diff:"medium", q:"Using AI to convert a lengthy expense receipt list into a formatted expense report is an example of:", options:["An automated workflow that summarizes and organizes information","A physical security control","A biometric authentication method","A network firewall rule"], answer:0, explain:"<strong>An automated workflow that summarizes and organizes information</strong> describes AI turning raw receipts into a structured report, a practical time-saving automation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A physical security control</b>: a physical control protects tangible assets and is unrelated to processing receipts.</span><span class='qd'><b>A biometric authentication method</b>: biometrics verify identity and have nothing to do with expense reports.</span><span class='qd'><b>A network firewall rule</b>: a firewall rule filters traffic, not expense data.</span>" },
{ id:"D5-050", domain:5, obj:"5.5", diff:"easy", q:"When AI drafts an email for you, what is the best final step before sending it?", options:["Review and edit it for accuracy and tone","Send it instantly without reading it","Delete it because AI cannot write email","Forward it to everyone in the company"], answer:0, explain:"<strong>Review and edit it for accuracy and tone</strong> ensures the message is correct and appropriate before it goes out under your name.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Send it instantly without reading it</b>: sending unreviewed AI text risks errors or an inappropriate tone.</span><span class='qd'><b>Delete it because AI cannot write email</b>: AI can draft email effectively; deleting it wastes the help.</span><span class='qd'><b>Forward it to everyone in the company</b>: mass-forwarding a draft is inappropriate and unnecessary.</span>" },
{ id:"D5-051", domain:5, obj:"5.1", diff:"medium", q:"An employee wants to troubleshoot a bug and considers pasting a code snippet that includes a live API key. What is the safest choice?", options:["Remove or replace the API key before sharing the snippet","Paste it as-is so the AI can fully diagnose the issue","Share the key in a separate message for safety","Post the key publicly so others can help too"], answer:0, explain:"<strong>Remove or replace the API key before sharing the snippet</strong> is safest because an API key is a secret credential that could let others access systems if exposed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paste it as-is so the AI can fully diagnose the issue</b>: full context is not worth exposing a live credential to a third-party service.</span><span class='qd'><b>Share the key in a separate message for safety</b>: putting the key in another message still submits the secret to the service.</span><span class='qd'><b>Post the key publicly so others can help too</b>: publishing a live key openly is the most dangerous option of all.</span>" },
{ id:"D5-052", domain:5, obj:"5.1", diff:"hard", q:"A remote worker uses a public AI note-taker that records and transcribes every meeting, including confidential strategy calls, and stores transcripts on the vendor's servers. What is the primary privacy risk?", options:["The transcripts load slowly","The audio quality may be poor","Confidential business discussions are stored on a third-party system outside company control","The worker will forget the meeting"], answer:2, explain:"<strong>Confidential business discussions are stored on a third-party system outside company control</strong>, exposing sensitive strategy to a vendor that could be breached or could reuse the data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The transcripts load slowly</b>: load speed is a convenience issue, not a privacy risk.</span><span class='qd'><b>The audio quality may be poor</b>: audio quality affects usefulness, not data confidentiality.</span><span class='qd'><b>The worker will forget the meeting</b>: memory is unrelated to where the confidential data is stored.</span>" },
{ id:"D5-053", domain:5, obj:"5.1", diff:"medium", q:"Which of the following would be the safest information to enter into a public AI chatbot?", options:["A general question about writing a professional thank-you note","Your bank account number and PIN","A colleague's private medical diagnosis","Your company's unreleased product roadmap"], answer:0, explain:"<strong>A general question about writing a professional thank-you note</strong> contains no sensitive data and is a perfectly safe, appropriate use of a public AI tool.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Your bank account number and PIN</b>: banking credentials are highly sensitive and must never be shared.</span><span class='qd'><b>A colleague's private medical diagnosis</b>: health information is sensitive personal data protected by privacy laws.</span><span class='qd'><b>Your company's unreleased product roadmap</b>: confidential business plans should not be exposed to a third-party service.</span>" },
{ id:"D5-054", domain:5, obj:"5.1", diff:"easy", q:"What does a privacy policy on an AI service primarily tell you?", options:["How the service collects, uses, stores, and shares your data","How to reset your password","The company's stock price","The AI's training schedule"], answer:0, explain:"<strong>How the service collects, uses, stores, and shares your data</strong> is the core purpose of a privacy policy, helping you decide what is safe to submit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>How to reset your password</b>: password resets are covered in account help, not the privacy policy.</span><span class='qd'><b>The company's stock price</b>: financial figures are not part of a privacy policy.</span><span class='qd'><b>The AI's training schedule</b>: internal training schedules are not what a privacy policy discloses.</span>" },
{ id:"D5-055", domain:5, obj:"5.1", diff:"hard", q:"An organization worries that employees entering client data into AI tools could enable tracking and profiling of those clients. Which control most directly reduces this risk?", options:["Buying faster laptops","Increasing the office Wi-Fi speed","Prohibiting entry of personal client data into public AI tools and using vetted platforms","Printing all client data on paper"], answer:2, explain:"<strong>Prohibiting entry of personal client data into public AI tools and using vetted platforms</strong> directly limits how client data leaves the organization, reducing tracking and profiling exposure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Buying faster laptops</b>: hardware speed does not affect where client data is sent.</span><span class='qd'><b>Increasing the office Wi-Fi speed</b>: faster Wi-Fi has no bearing on data privacy exposure.</span><span class='qd'><b>Printing all client data on paper</b>: printing data does not prevent it from being entered into AI tools and adds new risks.</span>" },
{ id:"D5-056", domain:5, obj:"5.1", diff:"medium", q:"Why is it risky to assume that anything you type into a public AI chatbot is completely private?", options:["Inputs may be logged, retained, reviewed, or used to train the model","Chatbots physically print your messages in the lobby","The text turns into audio automatically","Private mode is the default for all AI tools"], answer:0, explain:"<strong>Inputs may be logged, retained, reviewed, or used to train the model</strong>, so treating everything you type as private can lead to unintended exposure of sensitive data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Chatbots physically print your messages in the lobby</b>: this is not how AI services work and is not the real risk.</span><span class='qd'><b>The text turns into audio automatically</b>: automatic audio conversion is not what makes chatbot input non-private.</span><span class='qd'><b>Private mode is the default for all AI tools</b>: many tools retain and may use inputs by default, so privacy is not guaranteed.</span>" },
{ id:"D5-057", domain:5, obj:"5.1", diff:"easy", q:"Which action best protects sensitive data when using AI at work?", options:["Enter every detail so answers are more accurate","Include passwords to give the AI full access","Only enter information you would be comfortable sharing publicly","Paste entire confidential files by default"], answer:2, explain:"<strong>Only enter information you would be comfortable sharing publicly</strong> is a simple, effective rule that keeps sensitive data out of third-party AI systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Enter every detail so answers are more accurate</b>: entering everything can expose confidential data unnecessarily.</span><span class='qd'><b>Include passwords to give the AI full access</b>: sharing passwords is a serious security risk and is never appropriate.</span><span class='qd'><b>Paste entire confidential files by default</b>: defaulting to full confidential files maximizes exposure risk.</span>" },
{ id:"D5-058", domain:5, obj:"5.1", diff:"hard", q:"A manager insists that using a free consumer AI app for HR records is fine because &quot;the company is small and no one will notice.&quot; What is the strongest counterargument?", options:["Small companies are exempt from privacy laws","No one uses free apps for HR","Company size does not remove legal obligations, and HR records contain protected personal data","The app will automatically anonymize everything"], answer:2, explain:"<strong>Company size does not remove legal obligations, and HR records contain protected personal data</strong>, so the sensitivity of the data and applicable laws still require careful, compliant handling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Small companies are exempt from privacy laws</b>: many privacy obligations apply regardless of company size.</span><span class='qd'><b>No one uses free apps for HR</b>: whether others use them is irrelevant to the legal and privacy risk.</span><span class='qd'><b>The app will automatically anonymize everything</b>: consumer apps do not reliably anonymize the data you submit.</span>" },
{ id:"D5-059", domain:5, obj:"5.1", diff:"medium", q:"You want AI feedback on a resume that lists your home address and phone number. What is the most privacy-conscious approach?", options:["Include all details so the AI can format them","Add even more personal data for context","Remove personal contact details before pasting the resume for feedback","Post the resume with all details on a public forum"], answer:2, explain:"<strong>Remove personal contact details before pasting the resume for feedback</strong> lets you get useful help while keeping identifying personal data out of a third-party service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Include all details so the AI can format them</b>: the AI does not need your real address to give feedback on content.</span><span class='qd'><b>Add even more personal data for context</b>: adding more personal data increases exposure with no benefit.</span><span class='qd'><b>Post the resume with all details on a public forum</b>: publicly posting personal contact data invites misuse.</span>" },
{ id:"D5-060", domain:5, obj:"5.1", diff:"easy", q:"Which of the following is considered confidential company information that should not go into a public AI tool?", options:["A press release already published on the website","The company's public phone number","Unreleased financial results","A publicly posted job listing"], answer:2, explain:"<strong>Unreleased financial results</strong> are highly confidential and could cause harm or legal issues if exposed before official release.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A press release already published on the website</b>: a published press release is already public information.</span><span class='qd'><b>The company's public phone number</b>: a public phone number is meant to be shared.</span><span class='qd'><b>A publicly posted job listing</b>: a public job listing is already available to anyone.</span>" },
{ id:"D5-061", domain:5, obj:"5.2", diff:"medium", q:"You used AI to generate background music for a company video. What should you confirm before publishing?", options:["That the music is exactly 3 minutes long","That the file name is short","That you have the rights to use the music commercially under the tool's license","That the music is in stereo"], answer:2, explain:"<strong>That you have the rights to use the music commercially under the tool's license</strong> is essential because using AI-generated media commercially may be limited by the provider's terms.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>That the music is exactly 3 minutes long</b>: length is an editing detail, not a rights concern.</span><span class='qd'><b>That the file name is short</b>: file naming has nothing to do with usage rights.</span><span class='qd'><b>That the music is in stereo</b>: audio channels are a technical detail unrelated to licensing.</span>" },
{ id:"D5-062", domain:5, obj:"5.2", diff:"hard", q:"A marketing team prompts an AI to &quot;write ad copy just like [famous brand's] slogans&quot; and the output closely echoes a trademarked tagline. What is the main risk?", options:["The ad will be too short","The AI will refuse future requests","Reproducing a trademarked tagline can constitute trademark infringement","The font will be inconsistent"], answer:2, explain:"<strong>Reproducing a trademarked tagline can constitute trademark infringement</strong>, because closely copying a protected brand slogan for your own ads can violate the trademark holder's rights.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The ad will be too short</b>: length is unrelated to the trademark risk.</span><span class='qd'><b>The AI will refuse future requests</b>: a possible refusal is not the legal risk being described.</span><span class='qd'><b>The font will be inconsistent</b>: font choice has nothing to do with infringing a tagline.</span>" },
{ id:"D5-063", domain:5, obj:"5.2", diff:"easy", q:"Presenting AI-generated work as entirely your own without any acknowledgment, when your school or employer requires disclosure, is best described as:", options:["A firewall misconfiguration","A hardware failure","A potential academic or professional integrity violation","A backup error"], answer:2, explain:"<strong>A potential academic or professional integrity violation</strong> can occur when disclosure is required but AI involvement is hidden, which may breach honesty rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A firewall misconfiguration</b>: a firewall issue is a network problem, not an integrity matter.</span><span class='qd'><b>A hardware failure</b>: hardware failure is a technical fault unrelated to disclosure.</span><span class='qd'><b>A backup error</b>: a backup error concerns data recovery, not honesty about authorship.</span>" },
{ id:"D5-064", domain:5, obj:"5.2", diff:"medium", q:"Before reusing text an AI produced that appears to quote a book, what is the responsible step regarding copyright?", options:["Assume all quotes are free to use since AI provided them","Change one word so copyright no longer applies","Verify the source and ensure any quoted material is used and attributed properly","Publish it and remove the quotation marks"], answer:2, explain:"<strong>Verify the source and ensure any quoted material is used and attributed properly</strong> respects copyright and prevents passing off protected text without proper credit or permission.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume all quotes are free to use since AI provided them</b>: AI providing a quote does not grant you the right to use copyrighted text.</span><span class='qd'><b>Change one word so copyright no longer applies</b>: minor edits do not remove copyright protection from a work.</span><span class='qd'><b>Publish it and remove the quotation marks</b>: stripping quotation marks hides the source and can constitute plagiarism.</span>" },
{ id:"D5-065", domain:5, obj:"5.2", diff:"hard", q:"A publisher wants to sell a book of AI-generated short stories and is unsure who owns the content. What is the most responsible first step?", options:["Sell it immediately and address ownership only if sued","Assume the AI company owns nothing and you own everything automatically","Review the AI tool's terms of use and consult guidance on AI content ownership before selling","Claim a famous author wrote it"], answer:2, explain:"<strong>Review the AI tool's terms of use and consult guidance on AI content ownership before selling</strong> is responsible because ownership of AI-generated works can be uncertain and governed by the provider's terms.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sell it immediately and address ownership only if sued</b>: acting first invites legal trouble that due diligence could prevent.</span><span class='qd'><b>Assume the AI company owns nothing and you own everything automatically</b>: ownership is not automatic and depends on terms and law.</span><span class='qd'><b>Claim a famous author wrote it</b>: falsely attributing authorship is dishonest and potentially illegal.</span>" },
{ id:"D5-066", domain:5, obj:"5.2", diff:"medium", q:"Which of the following best reflects responsible use of AI-generated images at work?", options:["Use any AI image freely because AI images are always free","Remove all metadata so no one can trace the image","Confirm licensing terms and usage rights before using them in official materials","Sell the images as stock photos without checking terms"], answer:2, explain:"<strong>Confirm licensing terms and usage rights before using them in official materials</strong> ensures you comply with the provider's rules and avoid infringement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use any AI image freely because AI images are always free</b>: AI images are not always free of usage restrictions.</span><span class='qd'><b>Remove all metadata so no one can trace the image</b>: stripping metadata to hide origins is not responsible and does not grant usage rights.</span><span class='qd'><b>Sell the images as stock photos without checking terms</b>: reselling without confirming rights can violate the license.</span>" },
{ id:"D5-067", domain:5, obj:"5.2", diff:"easy", q:"Using material generated or gathered by AI that you do not have permission to use may result in:", options:["Faster internet speeds","Improved battery life","Copyright or licensing infringement","A stronger Wi-Fi signal"], answer:2, explain:"<strong>Copyright or licensing infringement</strong> can result from using content without the necessary rights, which carries legal and financial consequences.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Faster internet speeds</b>: internet speed is unrelated to using unlicensed content.</span><span class='qd'><b>Improved battery life</b>: battery life has nothing to do with copyright.</span><span class='qd'><b>A stronger Wi-Fi signal</b>: Wi-Fi strength is unrelated to licensing rights.</span>" },
{ id:"D5-068", domain:5, obj:"5.2", diff:"hard", q:"A team fine-tunes an AI on a large collection of copyrighted articles they scraped without permission, then sells the outputs. What is the core legal concern?", options:["The model will train too quickly","The outputs will be too accurate","The team will run out of storage","Using copyrighted material without a license or permission can infringe the owners' rights"], answer:3, explain:"<strong>Using copyrighted material without a license or permission can infringe the owners' rights</strong>, because incorporating protected works without authorization and profiting from the results raises serious infringement issues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model will train too quickly</b>: training speed is not a legal concern.</span><span class='qd'><b>The outputs will be too accurate</b>: accuracy does not create a copyright problem by itself.</span><span class='qd'><b>The team will run out of storage</b>: storage capacity is a technical issue, not the legal risk described.</span>" },
{ id:"D5-069", domain:5, obj:"5.2", diff:"medium", q:"Why should you check an AI tool's terms of use before relying on its outputs for business?", options:["Terms guarantee the content will go viral","Terms replace the need for any editing","Terms may define ownership, permitted uses, and restrictions on the content","Terms are only relevant for personal hobbies"], answer:2, explain:"<strong>Terms may define ownership, permitted uses, and restrictions on the content</strong>, so reviewing them tells you what you can legally do with the outputs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Terms guarantee the content will go viral</b>: terms of use make no promises about popularity.</span><span class='qd'><b>Terms replace the need for any editing</b>: you still need to review and edit outputs regardless of terms.</span><span class='qd'><b>Terms are only relevant for personal hobbies</b>: terms are especially important for business and commercial use.</span>" },
{ id:"D5-070", domain:5, obj:"5.2", diff:"easy", q:"Which practice helps you use AI content ethically and legally?", options:["Copy freely and never credit anyone","Assume all AI output is fact and legally unrestricted","Verify accuracy, respect copyright, and disclose AI use when appropriate","Hide the use of AI in every situation"], answer:2, explain:"<strong>Verify accuracy, respect copyright, and disclose AI use when appropriate</strong> combines the key habits of responsible, lawful AI use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Copy freely and never credit anyone</b>: copying without credit can be plagiarism and infringement.</span><span class='qd'><b>Assume all AI output is fact and legally unrestricted</b>: AI output can be wrong and legally restricted.</span><span class='qd'><b>Hide the use of AI in every situation</b>: concealing AI use where disclosure is expected is not ethical.</span>" },
{ id:"D5-071", domain:5, obj:"5.3", diff:"medium", q:"An employee finds a new AI plugin that connects directly to the company's email system. What should they do before installing it?", options:["Install it and grant it full access right away","Share their password with the plugin to speed setup","Get approval from IT/security to ensure it meets policy and security requirements","Assume any plugin in an app store is pre-approved"], answer:2, explain:"<strong>Get approval from IT/security to ensure it meets policy and security requirements</strong> is essential because a plugin with email access could expose sensitive data if it is not vetted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Install it and grant it full access right away</b>: granting full access to an unvetted plugin is a major security risk.</span><span class='qd'><b>Share their password with the plugin to speed setup</b>: sharing a password is dangerous and unnecessary.</span><span class='qd'><b>Assume any plugin in an app store is pre-approved</b>: app store availability does not mean your company has approved it.</span>" },
{ id:"D5-072", domain:5, obj:"5.3", diff:"easy", q:"HIPAA is a regulation most concerned with protecting which type of information?", options:["Public marketing slogans","Weather data","Protected health information","Restaurant menus"], answer:2, explain:"<strong>Protected health information</strong> is the focus of HIPAA, which sets rules for the privacy and security of medical data in the United States.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public marketing slogans</b>: slogans are public and not covered by HIPAA.</span><span class='qd'><b>Weather data</b>: weather data is public and not health information.</span><span class='qd'><b>Restaurant menus</b>: menus are public and unrelated to HIPAA.</span>" },
{ id:"D5-073", domain:5, obj:"5.3", diff:"hard", q:"A global company must comply with GDPR for its EU customers. An employee wants to feed EU customer records into a U.S.-based public AI tool. What is the main compliance issue?", options:["The tool might use a different currency","The records are in the wrong font","The AI cannot understand European names","Transferring and processing EU personal data this way may violate GDPR requirements"], answer:3, explain:"<strong>Transferring and processing EU personal data this way may violate GDPR requirements</strong>, because GDPR imposes strict rules on how EU personal data is handled and transferred.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The tool might use a different currency</b>: currency has nothing to do with data protection compliance.</span><span class='qd'><b>The records are in the wrong font</b>: font is irrelevant to GDPR obligations.</span><span class='qd'><b>The AI cannot understand European names</b>: language capability is not the compliance concern.</span>" },
{ id:"D5-074", domain:5, obj:"5.3", diff:"medium", q:"Your company's acceptable use policy says AI tools may not be used for certain confidential projects. You are assigned such a project. What should you do?", options:["Use AI anyway since it saves time","Ask the AI to keep the project secret","Follow the policy and do not use AI tools for that project","Use a personal device so the policy does not count"], answer:2, explain:"<strong>Follow the policy and do not use AI tools for that project</strong> respects the organization's rules, which exist to protect especially sensitive work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use AI anyway since it saves time</b>: convenience does not justify violating an explicit policy.</span><span class='qd'><b>Ask the AI to keep the project secret</b>: a request to the AI does not make prohibited use compliant.</span><span class='qd'><b>Use a personal device so the policy does not count</b>: switching devices to evade policy is still a violation.</span>" },
{ id:"D5-075", domain:5, obj:"5.3", diff:"easy", q:"Which is the best example of following company AI policy?", options:["Installing any AI app you find interesting","Entering client secrets into random chatbots","Using only approved AI tools and checking with IT when unsure","Ignoring policy because AI is new"], answer:2, explain:"<strong>Using only approved AI tools and checking with IT when unsure</strong> demonstrates compliance and a responsible mindset toward company rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Installing any AI app you find interesting</b>: installing unapproved apps violates policy and adds risk.</span><span class='qd'><b>Entering client secrets into random chatbots</b>: exposing client secrets breaches confidentiality and policy.</span><span class='qd'><b>Ignoring policy because AI is new</b>: novelty is not an excuse to ignore governance.</span>" },
{ id:"D5-076", domain:5, obj:"5.3", diff:"hard", q:"A department wants to roll out an AI tool company-wide. Which step best ensures responsible, compliant adoption?", options:["Deploy it to everyone first and review policy later","Let each employee decide their own data rules","Skip legal review to launch faster","Assess the tool against security, privacy, and regulatory requirements before deployment"], answer:3, explain:"<strong>Assess the tool against security, privacy, and regulatory requirements before deployment</strong> ensures the tool meets obligations before company data flows through it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deploy it to everyone first and review policy later</b>: deploying before review can expose data and create violations.</span><span class='qd'><b>Let each employee decide their own data rules</b>: inconsistent, individual rules create gaps and compliance risk.</span><span class='qd'><b>Skip legal review to launch faster</b>: skipping legal review risks serious regulatory problems.</span>" },
{ id:"D5-077", domain:5, obj:"5.3", diff:"medium", q:"Why might an organization maintain a list of approved AI tools rather than allowing any tool?", options:["To make employees' work slower","To increase the company's electricity bill","To ensure tools meet security, privacy, and compliance standards","To limit creativity for its own sake"], answer:2, explain:"<strong>To ensure tools meet security, privacy, and compliance standards</strong> is the purpose of an approved list, which reduces risk from unvetted software.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make employees' work slower</b>: the goal is safe enablement, not slowing people down.</span><span class='qd'><b>To increase the company's electricity bill</b>: cost of power is unrelated to approving tools.</span><span class='qd'><b>To limit creativity for its own sake</b>: approval protects data; it is not meant to stifle creativity arbitrarily.</span>" },
{ id:"D5-078", domain:5, obj:"5.3", diff:"easy", q:"If your company has no clear guidance on whether a specific AI use is allowed, the safest first move is to:", options:["Proceed and hope it is fine","Post the question to a public forum with company data attached","Ask your manager or IT/compliance for direction","Assume it is banned and quit the task entirely"], answer:2, explain:"<strong>Ask your manager or IT/compliance for direction</strong> gets you authoritative guidance and prevents an accidental policy or legal violation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Proceed and hope it is fine</b>: proceeding without guidance risks a violation.</span><span class='qd'><b>Post the question to a public forum with company data attached</b>: attaching company data to a public post is itself a data exposure.</span><span class='qd'><b>Assume it is banned and quit the task entirely</b>: abandoning the task is unnecessary when you can simply ask.</span>" },
{ id:"D5-079", domain:5, obj:"5.3", diff:"hard", q:"A compliance officer reviews AI use and finds employees pasting regulated data into consumer chatbots. Which corrective measure most directly addresses the root cause?", options:["Buy everyone new monitors","Turn off the office lights at night","Ask employees to type more slowly","Provide approved tools plus training on what data is prohibited, and enforce the policy"], answer:3, explain:"<strong>Provide approved tools plus training on what data is prohibited, and enforce the policy</strong> addresses the root cause by giving safe alternatives, clear rules, and accountability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Buy everyone new monitors</b>: monitors do not change what data employees paste into tools.</span><span class='qd'><b>Turn off the office lights at night</b>: lighting is irrelevant to data handling behavior.</span><span class='qd'><b>Ask employees to type more slowly</b>: typing speed has nothing to do with preventing prohibited data entry.</span>" },
{ id:"D5-080", domain:5, obj:"5.3", diff:"medium", q:"Which scenario shows the responsible-use mindset toward company compliance?", options:["An employee hides their AI use to avoid oversight","An employee shares regulated data with any tool that seems convenient","Before using an AI tool for regulated data, an employee confirms it is approved and permitted","An employee disables company security software to use a new AI app"], answer:2, explain:"<strong>Before using an AI tool for regulated data, an employee confirms it is approved and permitted</strong> reflects the responsible-use mindset of checking compliance before acting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An employee hides their AI use to avoid oversight</b>: concealing use undermines governance and is irresponsible.</span><span class='qd'><b>An employee shares regulated data with any tool that seems convenient</b>: convenience-driven sharing of regulated data risks violations.</span><span class='qd'><b>An employee disables company security software to use a new AI app</b>: disabling security controls creates serious risk.</span>" },
{ id:"D5-081", domain:5, obj:"5.4", diff:"medium", q:"You ask AI for a summary of a research paper and it invents citations that do not exist. What is the correct interpretation and response?", options:["The citations must be real because the AI sounds confident","This proves AI cannot summarize anything","Ignore it and submit the summary as-is","This is a hallucination; verify all citations against the real paper before using them"], answer:3, explain:"<strong>This is a hallucination; verify all citations against the real paper before using them</strong> is correct because AI can fabricate references, so you must confirm them against the source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The citations must be real because the AI sounds confident</b>: confident tone does not make fabricated citations real.</span><span class='qd'><b>This proves AI cannot summarize anything</b>: AI can summarize; the issue is verifying invented details, not total incapability.</span><span class='qd'><b>Ignore it and submit the summary as-is</b>: submitting fabricated citations spreads false information.</span>" },
{ id:"D5-082", domain:5, obj:"5.4", diff:"hard", q:"An AI resume screener was trained mostly on past hires from one demographic and now favors similar candidates. What responsible action addresses this bias?", options:["Trust the tool since it learned from real data","Use it faster to hire more people","Hide the bias from leadership","Audit the tool for bias, keep humans in the loop, and adjust or stop using it if it discriminates"], answer:3, explain:"<strong>Audit the tool for bias, keep humans in the loop, and adjust or stop using it if it discriminates</strong> is responsible because detecting and correcting biased outcomes protects fairness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust the tool since it learned from real data</b>: real historical data can embed and perpetuate bias.</span><span class='qd'><b>Use it faster to hire more people</b>: speeding up a biased tool amplifies unfair outcomes.</span><span class='qd'><b>Hide the bias from leadership</b>: concealing bias prevents it from being corrected and can cause legal harm.</span>" },
{ id:"D5-083", domain:5, obj:"5.4", diff:"easy", q:"When AI gives you information for an important decision, the best habit is to:", options:["Accept it as final truth immediately","Never question anything the AI says","Delete it so no one else can check","Double-check it against reliable sources before acting"], answer:3, explain:"<strong>Double-check it against reliable sources before acting</strong> protects you from acting on incorrect or biased AI output in important matters.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept it as final truth immediately</b>: AI can be wrong, so accepting it blindly is risky.</span><span class='qd'><b>Never question anything the AI says</b>: questioning output is a core part of responsible use.</span><span class='qd'><b>Delete it so no one else can check</b>: deleting it prevents verification, which is the opposite of good practice.</span>" },
{ id:"D5-084", domain:5, obj:"5.4", diff:"medium", q:"A customer service AI occasionally gives incorrect policy information to customers. What is the responsible way to handle this?", options:["Let it keep giving wrong answers to save effort","Blame customers for believing it","Remove the human support option entirely","Report the errors, verify policy details with authoritative sources, and correct the AI or its guidance"], answer:3, explain:"<strong>Report the errors, verify policy details with authoritative sources, and correct the AI or its guidance</strong> addresses the problem and protects customers from misinformation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let it keep giving wrong answers to save effort</b>: allowing ongoing errors harms customers and the company.</span><span class='qd'><b>Blame customers for believing it</b>: customers reasonably trust official channels; blaming them is inappropriate.</span><span class='qd'><b>Remove the human support option entirely</b>: removing human help worsens the impact of AI errors.</span>" },
{ id:"D5-085", domain:5, obj:"5.4", diff:"hard", q:"A manager wants to fully automate performance reviews using AI scores with no human input. Why is this risky?", options:["AI reviews are always too generous","Automation makes reviews take longer","Employees prefer no feedback at all","AI can be biased or inaccurate, and consequential decisions about people need human judgment"], answer:3, explain:"<strong>AI can be biased or inaccurate, and consequential decisions about people need human judgment</strong>, so removing human oversight from evaluations risks unfair and harmful outcomes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI reviews are always too generous</b>: AI reviews are not uniformly generous; the concern is bias and error in either direction.</span><span class='qd'><b>Automation makes reviews take longer</b>: the risk is fairness and accuracy, not review duration.</span><span class='qd'><b>Employees prefer no feedback at all</b>: employee preference for no feedback is not the reason full automation is risky.</span>" },
{ id:"D5-086", domain:5, obj:"5.4", diff:"medium", q:"Which statement best captures why you should not treat AI as the final authority on facts?", options:["AI has access to every fact ever recorded","AI never makes mistakes on important topics","AI is legally certified to be always correct","AI can generate plausible but incorrect information, so verification is needed"], answer:3, explain:"<strong>AI can generate plausible but incorrect information, so verification is needed</strong> is the key reason to confirm important facts independently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI has access to every fact ever recorded</b>: AI does not have perfect or complete knowledge.</span><span class='qd'><b>AI never makes mistakes on important topics</b>: AI can and does err even on important topics.</span><span class='qd'><b>AI is legally certified to be always correct</b>: there is no such certification, and AI is not always correct.</span>" },
{ id:"D5-087", domain:5, obj:"5.4", diff:"easy", q:"If an AI tool produces content that seems biased or offensive, a responsible user should:", options:["Share it widely for laughs","Assume it must be acceptable","Repeat the prompt to get more of it","Report it and avoid using that output"], answer:3, explain:"<strong>Report it and avoid using that output</strong> helps address the problem and prevents spreading harmful or unfair content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Share it widely for laughs</b>: spreading offensive content causes harm.</span><span class='qd'><b>Assume it must be acceptable</b>: assuming bias is acceptable normalizes harmful output.</span><span class='qd'><b>Repeat the prompt to get more of it</b>: generating more biased content worsens the issue.</span>" },
{ id:"D5-088", domain:5, obj:"5.4", diff:"hard", q:"A bank uses AI to flag fraudulent transactions but human analysts still review flagged cases before freezing accounts. Why is this human-in-the-loop design responsible?", options:["It makes the AI run faster","It removes the need to train the AI","It guarantees no fraud will ever occur","It catches AI errors and prevents unfair harm from false positives before action is taken"], answer:3, explain:"<strong>It catches AI errors and prevents unfair harm from false positives before action is taken</strong>, so human review guards customers against incorrect automated decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the AI run faster</b>: adding human review does not speed up the AI and is not the purpose.</span><span class='qd'><b>It removes the need to train the AI</b>: the AI still needs training; human review complements it.</span><span class='qd'><b>It guarantees no fraud will ever occur</b>: no system can guarantee zero fraud.</span>" },
{ id:"D5-089", domain:5, obj:"5.4", diff:"medium", q:"An AI summarizes a contract and omits a key clause. What responsible-use lesson does this illustrate?", options:["AI summaries are always complete","Original documents are unnecessary once summarized","Omissions never matter in contracts","Always review AI output against the original for accuracy and completeness"], answer:3, explain:"<strong>Always review AI output against the original for accuracy and completeness</strong> is the lesson, since AI can leave out important details you must catch yourself.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI summaries are always complete</b>: AI summaries can omit key points, as shown.</span><span class='qd'><b>Original documents are unnecessary once summarized</b>: the original is essential for verifying the summary.</span><span class='qd'><b>Omissions never matter in contracts</b>: a missing clause in a contract can have major consequences.</span>" },
{ id:"D5-090", domain:5, obj:"5.4", diff:"hard", q:"A city plans to use AI to decide who receives housing assistance with no human review. Which concern is most important to raise?", options:["The AI might use too much electricity","The interface color scheme","The speed of form submission","Biased or incorrect AI decisions could unfairly deny vulnerable people essential support"], answer:3, explain:"<strong>Biased or incorrect AI decisions could unfairly deny vulnerable people essential support</strong>, making human oversight critical for such high-stakes, life-affecting determinations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI might use too much electricity</b>: energy use is not the primary fairness concern here.</span><span class='qd'><b>The interface color scheme</b>: visual design is trivial compared to the impact on people.</span><span class='qd'><b>The speed of form submission</b>: submission speed is irrelevant to the fairness of the decisions.</span>" },
{ id:"D5-091", domain:5, obj:"5.5", diff:"medium", q:"You want AI to help you study a complex topic for a certification. Which approach uses AI as an effective teacher?", options:["Ask it to take the exam for you dishonestly","Ask it to hide the material so you cannot study","Ask it to give you only the hardest question and no explanation","Ask it to explain concepts, quiz you, and clarify anything you get wrong"], answer:3, explain:"<strong>Ask it to explain concepts, quiz you, and clarify anything you get wrong</strong> uses AI as a patient, interactive tutor that reinforces learning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask it to take the exam for you dishonestly</b>: cheating defeats the purpose of learning and is unethical.</span><span class='qd'><b>Ask it to hide the material so you cannot study</b>: hiding material prevents learning entirely.</span><span class='qd'><b>Ask it to give you only the hardest question and no explanation</b>: withholding explanations does not help you understand the material.</span>" },
{ id:"D5-092", domain:5, obj:"5.5", diff:"easy", q:"Which is a practical example of using AI to overcome writer's block?", options:["Asking it to lock your keyboard","Asking it to delete your document","Asking it to make the screen go blank","Asking it to suggest an outline and opening paragraph for your report"], answer:3, explain:"<strong>Asking it to suggest an outline and opening paragraph for your report</strong> gives you momentum and a structure to build on, directly beating the blank page.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asking it to lock your keyboard</b>: locking the keyboard prevents you from writing at all.</span><span class='qd'><b>Asking it to delete your document</b>: deleting your work is counterproductive.</span><span class='qd'><b>Asking it to make the screen go blank</b>: a blank screen does nothing to help you start writing.</span>" },
{ id:"D5-093", domain:5, obj:"5.5", diff:"medium", q:"An automated workflow uses AI to generate captions for social media posts from short descriptions. What is the responsible final step?", options:["Post them automatically with zero human review","Assume captions never need checking","Post the same caption on every unrelated image","Have a person review the captions for accuracy and appropriateness before posting"], answer:3, explain:"<strong>Have a person review the captions for accuracy and appropriateness before posting</strong> catches errors or tone issues before content goes public.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Post them automatically with zero human review</b>: unreviewed posts can contain errors or inappropriate content.</span><span class='qd'><b>Assume captions never need checking</b>: AI-generated captions can be wrong or off-tone and do need checking.</span><span class='qd'><b>Post the same caption on every unrelated image</b>: reusing one caption everywhere ignores context and misinforms.</span>" },
{ id:"D5-094", domain:5, obj:"5.5", diff:"hard", q:"A team wants a repeatable AI workflow to turn customer support tickets into weekly summary reports. Which design is most effective and responsible?", options:["Feed full customer names and card numbers for detail","Generate a random report unrelated to the tickets","Publish the raw tickets publicly instead","Feed anonymized ticket data with clear instructions, then have a human review the summary"], answer:3, explain:"<strong>Feed anonymized ticket data with clear instructions, then have a human review the summary</strong> protects privacy, gives the AI proper context, and keeps a human check on the output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Feed full customer names and card numbers for detail</b>: including sensitive personal data creates a serious privacy risk.</span><span class='qd'><b>Generate a random report unrelated to the tickets</b>: a random report fails the goal of summarizing real tickets.</span><span class='qd'><b>Publish the raw tickets publicly instead</b>: publishing raw tickets exposes customer data and defeats the purpose.</span>" },
{ id:"D5-095", domain:5, obj:"5.5", diff:"easy", q:"Which of the following is a common time-saving AI automation in the workplace?", options:["Manually alphabetizing a physical filing cabinet","Repainting the conference room","Delivering mail between floors","Drafting meeting minutes from a transcript"], answer:3, explain:"<strong>Drafting meeting minutes from a transcript</strong> is a widely used AI automation that quickly converts spoken discussion into organized notes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manually alphabetizing a physical filing cabinet</b>: this is a manual physical task, not AI automation.</span><span class='qd'><b>Repainting the conference room</b>: painting is a physical chore AI cannot perform.</span><span class='qd'><b>Delivering mail between floors</b>: physical mail delivery is not an AI text automation.</span>" },
{ id:"D5-096", domain:5, obj:"5.5", diff:"medium", q:"A good brainstorming prompt to beat the blank page would ask the AI to:", options:["Produce one idea and refuse to offer alternatives","Insist there are no possible ideas","Repeat your exact words back with no additions","Generate several distinct ideas or approaches you can react to and refine"], answer:3, explain:"<strong>Generate several distinct ideas or approaches you can react to and refine</strong> gives you a range of starting points, which is the essence of AI-assisted brainstorming.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Produce one idea and refuse to offer alternatives</b>: a single idea limits the brainstorming benefit.</span><span class='qd'><b>Insist there are no possible ideas</b>: refusing to generate ideas defeats the purpose.</span><span class='qd'><b>Repeat your exact words back with no additions</b>: echoing your words adds nothing new to overcome the block.</span>" },
{ id:"D5-097", domain:5, obj:"5.5", diff:"hard", q:"Which workflow best demonstrates responsible AI automation for drafting expense reports?", options:["AI submits the report and reimburses funds automatically with no checks","AI invents plausible expense amounts to fill gaps","AI shares all receipts publicly to prove accuracy","AI compiles receipts into a draft report, and an employee verifies the figures before submitting"], answer:3, explain:"<strong>AI compiles receipts into a draft report, and an employee verifies the figures before submitting</strong> combines automation with human verification, ensuring accuracy before submission.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI submits the report and reimburses funds automatically with no checks</b>: automatic reimbursement without review invites fraud and errors.</span><span class='qd'><b>AI invents plausible expense amounts to fill gaps</b>: fabricating amounts is dishonest and inaccurate.</span><span class='qd'><b>AI shares all receipts publicly to prove accuracy</b>: publicly sharing receipts exposes sensitive financial data.</span>" },
{ id:"D5-098", domain:5, obj:"5.5", diff:"medium", q:"How does using AI as a patient teacher differ from simply searching the web?", options:["AI always gives a shorter version of a web page","AI refuses to answer follow-up questions","AI can only provide links, never explanations","AI can adapt explanations to your questions and re-explain in different ways interactively"], answer:3, explain:"<strong>AI can adapt explanations to your questions and re-explain in different ways interactively</strong>, offering a tailored, conversational learning experience beyond static search results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI always gives a shorter version of a web page</b>: AI does more than shorten pages; it explains and adapts.</span><span class='qd'><b>AI refuses to answer follow-up questions</b>: AI is well suited to follow-up questions, not refusing them.</span><span class='qd'><b>AI can only provide links, never explanations</b>: AI provides explanations directly, not just links.</span>" },
{ id:"D5-099", domain:5, obj:"5.5", diff:"easy", q:"Which of these best describes a good use case for AI at work?", options:["Making all final legal decisions without a lawyer","Storing customer passwords in a chat log","Approving payroll with no human oversight","Summarizing a long document into key points you then review"], answer:3, explain:"<strong>Summarizing a long document into key points you then review</strong> is a strong, low-risk use case that saves time while keeping a human in the loop.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Making all final legal decisions without a lawyer</b>: high-stakes legal decisions need professional judgment.</span><span class='qd'><b>Storing customer passwords in a chat log</b>: storing passwords in a chat log is a serious security risk.</span><span class='qd'><b>Approving payroll with no human oversight</b>: unsupervised payroll approval risks costly errors.</span>" },
{ id:"D5-100", domain:5, obj:"5.5", diff:"hard", q:"A project manager wants AI to reliably transform messy raw notes into polished meeting minutes each week. Which combination best ensures useful, responsible results?", options:["Provide nothing and expect accurate minutes","Include confidential client secrets to enrich the minutes","Publish the AI minutes company-wide without any review","Provide structured notes and clear formatting instructions, then review the minutes for accuracy and sensitive content"], answer:3, explain:"<strong>Provide structured notes and clear formatting instructions, then review the minutes for accuracy and sensitive content</strong> gives the AI the context it needs and keeps a human check on accuracy and confidentiality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Provide nothing and expect accurate minutes</b>: without source notes the AI cannot produce accurate minutes.</span><span class='qd'><b>Include confidential client secrets to enrich the minutes</b>: adding confidential secrets creates unnecessary exposure risk.</span><span class='qd'><b>Publish the AI minutes company-wide without any review</b>: skipping review can spread errors or sensitive information.</span>" }
);
